316→    /**
317→     * @param deckId Either a deck id or ALL_DECKS_ID
318→     * @param name Name of the deck, or localization of "all decks"
319→     */
320→    @Parcelize
321→    class SelectableDeck(val deckId: DeckId, val name: String) : Comparable<SelectableDeck>, Parcelable {
322→        /**
323→         * The name to be displayed to the user. Contains
324→         * only the sub-deck name with proper indentation
325→         * rather than the entire deck name.
326→         * Eg: foo::bar -> \t\tbar
327→         */
328→        @IgnoredOnParcel
329→        val displayName: String by lazy {
330→            val nameArr = name.split("::")
331→            "\t\t".repeat(nameArr.size - 1) + nameArr[nameArr.size - 1]
332→        }
333→
334→        constructor(d: DeckNameId) : this(d.id, d.name)
335→
336→        /** "All decks" comes first. Then usual deck name order.  */
337→        override fun compareTo(other: SelectableDeck): Int {
338→            if (deckId == ALL_DECKS_ID) {
339→                return if (other.deckId == ALL_DECKS_ID) {
340→                    0
341→                } else {
342→                    -1
343→                }
344→            }
345→            return if (other.deckId == ALL_DECKS_ID) {
346→                1
347→            } else {
348→                DeckNameComparator.INSTANCE.compare(name, other.name)
349→            }
350→        }
351→
352→        companion object {
353→            /**
354→             * @param filter A method deciding which deck to add
355→             * @return the list of all SelectableDecks from the collection satisfying filter
356→             */
357→            fun fromCollection(c: Collection, includeFiltered: Boolean): List<SelectableDeck> {
358→                val all = c.decks.allNamesAndIds(includeFiltered = includeFiltered)
359→                val ret: MutableList<SelectableDeck> = ArrayList(all.size)
360→                for (d in all) {
361→                    ret.add(SelectableDeck(d))
362→                }
363→                return ret
364→            }
365→        }
366→    }
367→
368→    fun interface DeckSelectionListener {
369→        fun onDeckSelected(deck: SelectableDeck?)
370→    }
371→
372→    companion object {
373→        const val ALL_DECKS_ID = 0L
374→        private const val SUMMARY_MESSAGE = "summaryMessage"
375→        private const val TITLE = "title"
376→        private const val KEEP_RESTORE_DEFAULT_BUTTON = "keepRestoreDefaultButton"
377→        private const val DECK_NAMES = "deckNames"
378→
379→        /**
380→         * A dialog which handles selecting a deck
381→         */
382→        fun newInstance(title: String, summaryMessage: String?, keepRestoreDefaultButton: Boolean, decks: List<SelectableDeck>): DeckSelectionDialog {
383→            val f = DeckSelectionDialog()
384→            val args = Bundle()
385→            args.putString(SUMMARY_MESSAGE, summaryMessage)
386→            args.putString(TITLE, title)
387→            args.putBoolean(KEEP_RESTORE_DEFAULT_BUTTON, keepRestoreDefaultButton)
388→            args.putParcelableArrayList(DECK_NAMES, ArrayList(decks))
389→            f.arguments = args
390→            return f
391→        }
392→    }
393→}
